class SpacingAroundColonRuleAnnotationTest {
    private val spacingAroundColonRuleAssertThat = assertThatRule { SpacingAroundColonRule() }

    @Test
    fun `Given annotation use-site targets with correct spacing`() {
        val code =
            """
            @file:JvmName("Foo")
            class Example(@field:Ann val foo: String, @get:Ann val bar: String)
            class Example {
                @set:[Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given annotation use-site targets with spacing before colon`() {
        val code =
            """
            @file :JvmName("Foo")
            class Example(@field :Ann val foo: String, @get :Ann val bar: String)
            class Example {
                @set :[Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            class Example(@field:Ann val foo: String, @get:Ann val bar: String)
            class Example {
                @set:[Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 6, "Unexpected spacing before \":\""),
                LintViolation(2, 21, "Unexpected spacing before \":\""),
                LintViolation(2, 42, "Unexpected spacing before \":\""),
                LintViolation(4, 8, "Unexpected spacing before \":\""),
            ).isFormattedAs(formattedCode)
    }

