        val code =
            """
            @file: JvmName("Foo")
            class Example(@field: Ann val foo: String, @get: Ann val bar: String)
            class Example {
                @set: [Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            class Example(@field:Ann val foo: String, @get:Ann val bar: String)
            class Example {
                @set:[Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 6, "Unexpected spacing after \":\""),
                LintViolation(2, 21, "Unexpected spacing after \":\""),
                LintViolation(2, 42, "Unexpected spacing after \":\""),
                LintViolation(4, 8, "Unexpected spacing after \":\""),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given annotation use-site targets with spacing on both sides of colon`() {
        val code =
            """
            @file : JvmName("Foo")
            class Example(@field : Ann val foo: String, @get : Ann val bar: String)
