            class Example {
                @set:[Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 7, "Unexpected spacing before \":\""),
                LintViolation(1, 7, "Unexpected spacing after \":\""),
                LintViolation(2, 22, "Unexpected spacing before \":\""),
                LintViolation(2, 22, "Unexpected spacing after \":\""),
                LintViolation(2, 50, "Unexpected spacing before \":\""),
                LintViolation(2, 50, "Unexpected spacing after \":\""),
                LintViolation(4, 10, "Unexpected spacing before \":\""),
                LintViolation(4, 10, "Unexpected spacing after \":\""),
            ).isFormattedAs(formattedCode)
